/** Predefined smart-home SVG icons for the icon picker */
/** Convert an SVG path to a data-URI string that <img> / Icon can display */
export function pathToDataUri(d) {
    const svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24"><path fill="currentColor" d="${d}"/></svg>`;
    return `data:image/svg+xml,${encodeURIComponent(svg)}`;
}
